/**
 * Generates src/utils/cliAssets.ts by embedding the built CLI bundle and the
 * agent discovery assets (SKILL.md, AGENTS.md snippet) as string constants that
 * LocalCliInstaller writes to a machine-global location on user action.
 *
 * Run AFTER scripts/build-cli.mjs:
 *   node scripts/build-cli.mjs && node scripts/generate-cli-content.mjs
 *
 * DO NOT edit src/utils/cliAssets.ts by hand — it is regenerated on build.
 */
import fs from 'fs';
import path from 'path';
import crypto from 'crypto';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.join(__dirname, '..');

function read(rel) {
    return fs.readFileSync(path.join(root, rel), 'utf-8');
}

/** Escape a string for embedding inside a template literal. */
function escapeForTemplate(content) {
    return content
        .replace(/\\/g, '\\\\')
        .replace(/`/g, '\\`')
        .replace(/\$\{/g, '\\${');
}

const cliJs = read('nexus-cli.js');
const skillMd = read('skill/SKILL.md');
const agentsMd = read('cli/agents-snippet.md');

// Every skill/playbooks/*.md (including the shared _preamble.md) → { filename: content }.
// The installer writes these to <dataDir>/skill/playbooks/ so `nexus playbook` can read them.
const playbooksDir = path.join(root, 'skill', 'playbooks');
const playbooks = fs.existsSync(playbooksDir)
    ? fs.readdirSync(playbooksDir)
          .filter((f) => f.endsWith('.md'))
          .sort()
          .map((f) => ({ file: f, content: read(path.join('skill', 'playbooks', f)) }))
    : [];

// Content hash lets the installer detect a stale on-disk copy and refresh it
// (machine-global + unsynced, so this is a simple content compare — no version skew).
const hasher = crypto
    .createHash('sha256')
    .update(cliJs)
    .update(skillMd)
    .update(agentsMd);
for (const p of playbooks) hasher.update(p.file).update(p.content);
const hash = hasher.digest('hex').slice(0, 16);

const playbooksLiteral = playbooks.length
    ? '{\n' + playbooks.map((p) => `    ${JSON.stringify(p.file)}: \`${escapeForTemplate(p.content)}\`,`).join('\n') + '\n}'
    : '{}';

const output = `/**
 * Auto-generated. Embedded assets for the Nexus local CLI bridge:
 * the bundled \`nexus\` CLI plus the agent discovery artifacts the installer
 * writes to a machine-global location.
 *
 * DO NOT EDIT MANUALLY — regenerated by scripts/generate-cli-content.mjs.
 * Generated: ${new Date().toISOString()}
 */

/** Combined content hash — used to detect and refresh a stale on-disk install. */
export const NEXUS_CLI_ASSETS_HASH = ${JSON.stringify(hash)};

/** Bundled standalone \`nexus\` CLI (written to <dataDir>/nexus-cli.js). */
export const NEXUS_CLI_JS = \`${escapeForTemplate(cliJs)}\`;

/** SKILL.md for Claude Code (written to <dataDir>/skill/SKILL.md). */
export const NEXUS_SKILL_MD = \`${escapeForTemplate(skillMd)}\`;

/** AGENTS.md pointer block for Codex / skill-less agents. */
export const NEXUS_AGENTS_MD = \`${escapeForTemplate(agentsMd)}\`;

/** Playbook markdown by filename (written to <dataDir>/skill/playbooks/). */
export const NEXUS_PLAYBOOKS: Record<string, string> = ${playbooksLiteral};
`;

fs.writeFileSync(path.join(root, 'src', 'utils', 'cliAssets.ts'), output, 'utf-8');
console.log('[generate-cli-content] wrote src/utils/cliAssets.ts (hash ' + hash + ')');
